package com.ploy.test;

import java.io.File;
import java.io.IOException;
import java.util.Arrays;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;
import org.apache.commons.lang3.StringUtils;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * Main application class with Java 11 patterns that can be migrated to Java 17.
 * Contains various code patterns that OpenRewrite can detect and transform:
 * - Optional usage patterns
 * - String operations that can use newer methods
 * - Stream API usage
 * - File operations that can be modernized
 */
public class App {
    private static final Logger logger = LoggerFactory.getLogger(App.class);

    public static void main(String[] args) {
        logger.info("Starting Ploy OpenRewrite Java 11 Test Application");

        App app = new App();
        app.run(args);

        logger.info("Application completed successfully");
    }

    public void run(String[] args) {
        // Process command line arguments
        List<String> arguments = Arrays.asList(args);
        processArguments(arguments);

        // Demonstrate various Java patterns
        demonstrateStringOperations();
        demonstrateOptionalUsage();
        demonstrateFileOperations();
        demonstrateStreamOperations();
    }

    /**
     * String operations that can benefit from Java 17+ improvements
     */
    private void demonstrateStringOperations() {
        String input = "  Hello World  ";

        // Use Apache Commons Lang for operations that Java 17+ has natively
        if (StringUtils.isBlank(input)) {
            logger.warn("Input string is blank");
            return;
        }

        String trimmed = StringUtils.trim(input);
        String[] parts = StringUtils.split(trimmed, " ");

        logger.info("Processed string: {}", String.join("-", parts));

        // Repeated string operations (could use String.repeat in Java 17+)
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 3; i++) {
            sb.append("=");
        }
        String separator = sb.toString();
        logger.info("Separator: {}", separator);
    }

    /**
     * Optional usage patterns that could be improved
     */
    private void demonstrateOptionalUsage() {
        Optional<String> maybeValue = findValue("test");

        // Pattern that can be simplified in newer Java versions
        if (maybeValue.isPresent()) {
            String value = maybeValue.get();
            logger.info("Found value: {}", value);
        } else {
            logger.info("No value found");
        }

        // Another pattern for Optional handling
        String result = maybeValue.map(String::toUpperCase).orElse("DEFAULT");
        logger.info("Result: {}", result);
    }

    private Optional<String> findValue(String key) {
        if ("test".equals(key)) {
            return Optional.of("test-value");
        }
        return Optional.empty();
    }

    /**
     * File operations using older patterns
     */
    private void demonstrateFileOperations() {
        try {
            File tempDir = new File(System.getProperty("java.io.tmpdir"));
            File[] files = tempDir.listFiles();

            if (files != null) {
                logger.info("Found {} files in temp directory", files.length);

                // Process files using older patterns
                for (File file : files) {
                    if (file.isFile() && file.getName().endsWith(".tmp")) {
                        logger.debug("Processing temp file: {}", file.getName());
                    }
                }
            }
        } catch (Exception e) {
            logger.error("Error processing files", e);
        }
    }

    /**
     * Stream operations that could benefit from newer Java features
     */
    private void demonstrateStreamOperations() {
        List<String> items = Arrays.asList("apple", "banana", "cherry", "date");

        // Filter and collect - could be improved with newer patterns
        List<String> filtered = items.stream()
            .filter(item -> item.length() > 4)
            .map(String::toUpperCase)
            .collect(Collectors.toList());

        logger.info("Filtered items: {}", filtered);

        // Count operations
        long count = items.stream()
            .filter(item -> item.startsWith("a"))
            .count();

        logger.info("Items starting with 'a': {}", count);
    }

    private void processArguments(List<String> args) {
        if (args.isEmpty()) {
            logger.info("No arguments provided");
            return;
        }

        logger.info("Processing {} arguments", args.size());
        args.forEach(arg -> logger.debug("Argument: {}", arg));
    }
}

package com.ploy.test;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import static org.junit.jupiter.api.Assertions.*;

import java.util.Arrays;
import java.util.List;
import java.util.Optional;

/**
 * Test class demonstrating Java 11 testing patterns.
 * Contains patterns that can be enhanced with Java 17+ features.
 */
class AppTest {

    private App app;

    @BeforeEach
    void setUp() {
        app = new App();
    }

    @Test
    @DisplayName("App should run without arguments")
    void testRunWithoutArguments() {
        // This should not throw any exceptions
        assertDoesNotThrow(() -> {
            app.run(new String[]{});
        });
    }

    @Test
    @DisplayName("App should handle command line arguments")
    void testRunWithArguments() {
        String[] args = {"arg1", "arg2", "test"};

        assertDoesNotThrow(() -> {
            app.run(args);
        });
    }

    @Test
    @DisplayName("Test string processing patterns")
    void testStringProcessing() {
        // Test patterns that could benefit from newer Java features
        String input = "  test string  ";

        // Simulate the string processing logic from App
        String trimmed = input.trim();
        assertFalse(trimmed.isEmpty());
        assertEquals("test string", trimmed);

        // Test string repetition (could use String.repeat in Java 17+)
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 5; i++) {
            sb.append("*");
        }
        String repeated = sb.toString();
        assertEquals("*****", repeated);
    }

    @Test
    @DisplayName("Test Optional usage patterns")
    void testOptionalPatterns() {
        // Test Optional patterns that could be improved
        Optional<String> present = Optional.of("value");
        Optional<String> empty = Optional.empty();

        assertTrue(present.isPresent());
        assertFalse(empty.isPresent());

        // Pattern that could be simplified
        String result;
        if (present.isPresent()) {
            result = present.get().toUpperCase();
        } else {
            result = "DEFAULT";
        }
        assertEquals("VALUE", result);

        // Better pattern but could still be improved in newer versions
        String betterResult = present.map(String::toUpperCase).orElse("DEFAULT");
        assertEquals("VALUE", betterResult);
    }

    @Test
    @DisplayName("Test collection processing")
    void testCollectionProcessing() {
        List<String> items = Arrays.asList("apple", "banana", "cherry");

        // Count items matching criteria
        long count = items.stream()
            .filter(item -> item.length() > 5)
            .count();

        assertEquals(2, count); // "banana" and "cherry"

        // Test list operations that could benefit from newer Java
        assertFalse(items.isEmpty());
        assertTrue(items.contains("apple"));

        // Convert to array (pattern that could be improved)
        String[] array = items.toArray(new String[0]);
        assertEquals(3, array.length);
    }

    @Test
    @DisplayName("Test exception handling patterns")
    void testExceptionHandling() {
        // Test exception patterns that could be enhanced
        assertThrows(IllegalArgumentException.class, () -> {
            throw new IllegalArgumentException("Test exception");
        });

        // Test null handling that could use newer Optional patterns
        String nullValue = null;
        String result = nullValue != null ? nullValue : "default";
        assertEquals("default", result);
    }
}
